        for (long long d = 2; d <= n / d / d + 1; ++d) {
            if (n % d != 0) continue;
            if ((n / d) % d == 0) {
                cout << d << ' ' << n / d / d << '\n';
            } else {
                long long p = integer_sqrt(n / d);
                cout << p << ' ' << d << '\n';
            }
            break;
        }
    }
    return 0;
}

