int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;
    const int MAXP = 1000000;
    vector<int> is_prime(MAXP + 1, 1), primes;
    is_prime[0] = is_prime[1] = 0;
    for (int i = 2; i <= MAXP; ++i) {
        if (!is_prime[i]) continue;
        primes.push_back(i);
        if (1LL * i * i <= MAXP) {
            for (long long j = 1LL * i * i; j <= MAXP; j += i) is_prime[(int)j] = 0;
        }
    }

    long long ans = 0;
    int p = (int)primes.size();
    for (int i = 0; i < p; ++i) {
        long long a = primes[i];
        if ((__int128)a * a * primes[i + 1] * primes[i + 2] * primes[i + 2] > n) break;
        for (int j = i + 1; j + 1 < p; ++j) {
            long long b = primes[j];
            __int128 minimum = (__int128)a * a * b * primes[j + 1] * primes[j + 1];
            if (minimum > n) break;
            long long limit = (long long)(n / ((__int128)a * a * b));
            long long root = sqrt((long double)limit);
            while ((root + 1) <= limit / (root + 1)) ++root;
            while (root > limit / root) --root;
            int upto = (int)(upper_bound(primes.begin() + j + 1, primes.end(), (int)root) - primes.begin());
            ans += max(0, upto - (j + 1));
        }
    }
    cout << ans << '\n';
    return 0;
}

