#include <stack>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <utility>
#include <vector>
using namespace std;

// 参考解：按题意实现核心算法。
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s, t;
    cin >> s >> t;
    vector<int> cs(26, 0), ct(26, 0);
    int ats = 0, att = 0;
    for (char ch : s) {
        if (ch == '@') ++ats;
        else ++cs[ch - 'a'];
    }
    for (char ch : t) {
        if (ch == '@') ++att;
        else ++ct[ch - 'a'];
    }
    string ok = "atcoder";
    set<int> flexible;
    for (char ch : ok) flexible.insert(ch - 'a');
    for (int i = 0; i < 26; ++i) {
        if (cs[i] == ct[i]) continue;
        if (!flexible.count(i)) {
            cout << "No\n";
            return 0;
        }
        if (cs[i] < ct[i]) ats -= ct[i] - cs[i];
        else att -= cs[i] - ct[i];
    }
    cout << (ats >= 0 && att >= 0 ? "Yes" : "No") << '\n';
    return 0;
}
